{
  "name": "BannerClone AI",
  "description": "An AI-powered design tool that clones the style of reference banners and adapts them to your specific products using Gemini Nano Banana Pro."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GeneratedImage {
  id: string;
  url: string;
  style: string;
}

export interface GenerationState {
  isGenerating: boolean;
  error: string | null;
  results: GeneratedImage[];
}

export type DesignStyle = 'Faithful Clone' | 'Modern Minimalist' | 'Bold & Vibrant' | 'Luxury & Elegant' | 'Creative Twist';

export const STYLES: DesignStyle[] = [
  'Faithful Clone',
  'Modern Minimalist',
  'Bold & Vibrant',
  'Luxury & Elegant',
  'Creative Twist'
];

import { GoogleGenAI } from "@google/genai";
import { DesignStyle } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using 'gemini-3-pro-image-preview' as requested for "nano banana pro" equivalent functionality
// capable of high fidelity image generation and understanding.
const MODEL_NAME = 'gemini-3-pro-image-preview';

/**
 * Clean base64 string to remove data URI prefix if present.
 */
const cleanBase64 = (base64: string): string => {
  return base64.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '');
};

export const generateBanner = async (
  referenceImage: string,
  productImage: string,
  userPrompt: string,
  style: DesignStyle
): Promise<string> => {
  try {
    const cleanRef = cleanBase64(referenceImage);
    const cleanProd = cleanBase64(productImage);

    // Construct a prompt that guides the model to "clone" the reference layout
    // but use the product image.
    const promptText = `
      Task: Create a professional advertisement banner.

      Inputs:
      1. First Image provided is the REFERENCE STYLE.
      2. Second Image provided is the PRODUCT.

      Directives:
      - Analyze the layout, typography, color palette, and composition of the REFERENCE STYLE image.
      - Create a NEW image that mimics this exact design style.
      - IMPORTANT: Replace the main subject/object in the reference with the PRODUCT from the second image.
      - Ensure the product looks naturally integrated into the lighting and perspective of the new design.
      - Design Variation: Apply a "${style}" approach to this adaptation.
      ${userPrompt ? `- Additional User Instructions: ${userPrompt}` : ''}

      Output:
      - A high-quality, high-resolution image.
    `;

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          { text: promptText },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: cleanRef,
            },
          },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: cleanProd,
            },
          },
        ],
      },
      config: {
        imageConfig: {
            aspectRatio: "3:4", // Standard poster/banner ratio. 
            imageSize: "1K"
        }
      }
    });

    // Parse the response to find the image
    const candidates = response.candidates;
    if (candidates && candidates.length > 0) {
      for (const part of candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useRef, useState } from 'react';

interface ImageUploadProps {
  label: string;
  description: string;
  image: string | null;
  onImageChange: (base64: string | null) => void;
}

export const ImageUpload: React.FC<ImageUploadProps> = ({
  label,
  description,
  image,
  onImageChange,
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    processFile(file);
  };

  const processFile = (file: File | undefined) => {
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      alert('Please upload an image file');
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      onImageChange(result);
    };
    reader.readAsDataURL(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    processFile(file);
  };

  return (
    <div className="flex flex-col gap-2 w-full">
      <label className="text-sm font-semibold text-gray-300 uppercase tracking-wider">
        {label}
      </label>
      <div
        className={`relative flex flex-col items-center justify-center w-full h-64 border-2 border-dashed rounded-xl transition-all duration-300 overflow-hidden cursor-pointer
          ${isDragging 
            ? 'border-blue-500 bg-blue-500/10' 
            : 'border-gray-600 bg-gray-800/50 hover:border-gray-500 hover:bg-gray-800'
          }
          ${image ? 'border-none' : ''}
        `}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        onClick={() => fileInputRef.current?.click()}
      >
        {image ? (
          <div className="relative w-full h-full group">
            <img 
              src={image} 
              alt="Uploaded" 
              className="w-full h-full object-contain p-2" 
            />
            <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                <span className="text-white font-medium">Click to replace</span>
            </div>
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center pt-5 pb-6 px-4 text-center">
            <svg
              className="w-10 h-10 mb-3 text-gray-400"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="2"
                d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"
              ></path>
            </svg>
            <p className="mb-2 text-sm text-gray-400">
              <span className="font-semibold">Click to upload</span> or drag and drop
            </p>
            <p className="text-xs text-gray-500">{description}</p>
          </div>
        )}
        <input
          ref={fileInputRef}
          type="file"
          className="hidden"
          accept="image/*"
          onChange={handleFileChange}
        />
      </div>
      {image && (
        <button 
            onClick={(e) => {
                e.stopPropagation();
                onImageChange(null);
            }}
            className="self-end text-xs text-red-400 hover:text-red-300 underline"
        >
            Remove Image
        </button>
      )}
    </div>
  );
};

import React from 'react';
import { GeneratedImage } from '../types';

interface GalleryProps {
  images: GeneratedImage[];
  isGenerating: boolean;
}

export const Gallery: React.FC<GalleryProps> = ({ images, isGenerating }) => {
  if (images.length === 0 && !isGenerating) {
    return null;
  }

  const downloadImage = (url: string, id: string) => {
    const link = document.createElement('a');
    link.href = url;
    link.download = `banner-clone-${id}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="mt-12 w-full">
      <h2 className="text-2xl font-bold mb-6 text-white flex items-center gap-2">
        <span>Generated Designs</span>
        {isGenerating && (
            <span className="text-sm font-normal text-blue-400 animate-pulse">
                (Processing variations...)
            </span>
        )}
      </h2>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
        {images.map((img) => (
          <div 
            key={img.id} 
            className="group relative bg-gray-800 rounded-xl overflow-hidden shadow-lg border border-gray-700 hover:border-blue-500 transition-all duration-300"
          >
            <div className="aspect-[3/4] w-full bg-gray-900 flex items-center justify-center overflow-hidden">
                <img
                  src={img.url}
                  alt={`Generated ${img.style}`}
                  className="w-full h-full object-cover"
                />
            </div>

            <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-end p-4">
              <span className="text-sm font-bold text-white mb-2">{img.style}</span>
              <button
                onClick={() => downloadImage(img.url, img.id)}
                className="w-full py-2 bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium rounded-lg shadow-lg transform translate-y-2 group-hover:translate-y-0 transition-transform"
              >
                Download
              </button>
            </div>
            <div className="p-3 bg-gray-800 border-t border-gray-700 md:hidden">
                 <p className="text-xs text-gray-400">{img.style}</p>
            </div>
          </div>
        ))}

        {isGenerating && Array.from({ length: 5 - images.length }).map((_, idx) => (
            <div key={`loading-${idx}`} className="bg-gray-800/50 rounded-xl border border-gray-700 aspect-[3/4] flex flex-col items-center justify-center animate-pulse p-4">
                <div className="w-12 h-12 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin mb-4"></div>
                <div className="h-2 w-2/3 bg-gray-700 rounded mb-2"></div>
                <div className="h-2 w-1/2 bg-gray-700 rounded"></div>
            </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ImageUpload } from './components/ImageUpload';
import { Gallery } from './components/Gallery';
import { generateBanner } from './services/geminiService';
import { GeneratedImage, GenerationState, STYLES } from './types';

const App: React.FC = () => {
  const [referenceImage, setReferenceImage] = useState<string | null>(null);
  const [productImage, setProductImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState<string>('');

  const [state, setState] = useState<GenerationState>({
    isGenerating: false,
    error: null,
    results: []
  });

  const handleGenerate = async () => {
    if (!referenceImage || !productImage) {
      setState(prev => ({ ...prev, error: 'Please upload both a reference image and a product image.' }));
      return;
    }

    setState({
      isGenerating: true,
      error: null,
      results: []
    });

    try {
      // Launch 5 parallel requests for different styles
      const promises = STYLES.map(async (style) => {
        try {
          // Use current inputs
          const resultBase64 = await generateBanner(
            referenceImage,
            productImage,
            prompt,
            style
          );

          const newImage: GeneratedImage = {
            id: crypto.randomUUID(),
            url: resultBase64,
            style: style
          };

          // Update state as images come in (progressive rendering)
          setState(prev => ({
            ...prev,
            results: [...prev.results, newImage]
          }));

          return newImage;
        } catch (err) {
          console.error(`Failed to generate for style ${style}`, err);
          return null; 
        }
      });

      await Promise.all(promises);

    } catch (error: any) {
      setState(prev => ({ 
        ...prev, 
        error: error.message || 'An unexpected error occurred during generation.' 
      }));
    } finally {
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-900 via-gray-800 to-black text-white p-4 md:p-8">
      <div className="max-w-7xl mx-auto">

        {/* Header */}
        <header className="mb-10 text-center">
          <h1 className="text-4xl md:text-5xl font-extrabold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-500 mb-4">
            BannerClone AI
          </h1>
          <p className="text-gray-400 max-w-2xl mx-auto text-lg">
            Upload a design reference and your product. We'll use <strong>Gemini Nano Banana Pro</strong> to magically clone the style for your brand.
          </p>
        </header>

        {/* Main Input Area */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Uploads */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-gray-800/50 backdrop-blur-sm p-6 rounded-2xl border border-gray-700 shadow-xl">
              <h2 className="text-xl font-bold mb-4 text-white flex items-center gap-2">
                <span className="bg-blue-500 rounded-full w-6 h-6 flex items-center justify-center text-xs">1</span>
                Upload Assets
              </h2>

              <div className="space-y-6">
                <ImageUpload
                  label="Reference Design"
                  description="Upload a Pinterest pin or banner style to copy"
                  image={referenceImage}
                  onImageChange={setReferenceImage}
                />
                <ImageUpload
                  label="Your Product"
                  description="Upload the product to feature in the design"
                  image={productImage}
                  onImageChange={setProductImage}
                />
              </div>
            </div>
          </div>

          {/* Right Column: Controls & Prompt */}
          <div className="lg:col-span-8 flex flex-col gap-6">
             <div className="bg-gray-800/50 backdrop-blur-sm p-6 rounded-2xl border border-gray-700 shadow-xl flex-grow">
               <div className="flex flex-col h-full justify-between">
                 <div>
                    <h2 className="text-xl font-bold mb-4 text-white flex items-center gap-2">
                        <span className="bg-purple-500 rounded-full w-6 h-6 flex items-center justify-center text-xs">2</span>
                        Customization
                    </h2>

                    <div className="mb-6">
                        <label htmlFor="prompt" className="block text-sm font-medium text-gray-300 mb-2">
                        Modifications (Optional)
                        </label>
                        <textarea
                        id="prompt"
                        rows={4}
                        className="w-full bg-gray-900 border border-gray-600 rounded-xl p-4 text-white placeholder-gray-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all resize-none"
                        placeholder="E.g., Make the background darker, add festive sparkles, change the mood to be more energetic..."
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        />
                    </div>
                 </div>

                 <div className="mt-4">
                     {state.error && (
                        <div className="mb-4 p-4 bg-red-500/20 border border-red-500/50 rounded-xl text-red-200 text-sm">
                            {state.error}
                        </div>
                     )}

                    <button
                        onClick={handleGenerate}
                        disabled={state.isGenerating || !referenceImage || !productImage}
                        className={`w-full py-4 px-6 rounded-xl font-bold text-lg shadow-lg transition-all duration-300 flex items-center justify-center gap-3
                        ${state.isGenerating || !referenceImage || !productImage
                            ? 'bg-gray-700 text-gray-400 cursor-not-allowed'
                            : 'bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white transform hover:scale-[1.01] hover:shadow-blue-500/25'
                        }`}
                    >
                        {state.isGenerating ? (
                            <>
                                <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                                </svg>
                                Generating 5 Variations...
                            </>
                        ) : (
                            <>
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09z" />
                                </svg>
                                Generate Variations
                            </>
                        )}
                    </button>
                    <p className="text-xs text-gray-500 text-center mt-3">
                        Generates 5 unique interpretations using Gemini Nano Banana Pro
                    </p>
                 </div>
               </div>
             </div>
          </div>
        </div>

        {/* Results Area */}
        <Gallery images={state.results} isGenerating={state.isGenerating} />

      </div>
    </div>
  );
};

export default App;

export interface GeneratedImage {
  id: string;
  url: string;
  style: string;
}

export interface GenerationState {
  isGenerating: boolean;
  error: string | null;
  results: GeneratedImage[];
}

export type DesignStyle = 'Faithful Clone' | 'Modern Minimalist' | 'Bold & Vibrant' | 'Luxury & Elegant' | 'Creative Twist';

export const STYLES: DesignStyle[] = [
  'Faithful Clone',
  'Modern Minimalist',
  'Bold & Vibrant',
  'Luxury & Elegant',
  'Creative Twist'
];

export interface GenerationSettings {
  theme: 'dark' | 'light';
  quantity: number;
  aspectRatio: '1:1' | '3:4' | '4:3' | '16:9' | '9:16';
  quality: '1K' | '2K' | '4K';
}

export const DEFAULT_SETTINGS: GenerationSettings = {
  theme: 'dark',
  quantity: 5,
  aspectRatio: '3:4',
  quality: '1K'
};

import { GoogleGenAI } from "@google/genai";
import { DesignStyle, GenerationSettings } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = 'gemini-3-pro-image-preview';

/**
 * Clean base64 string to remove data URI prefix if present.
 */
const cleanBase64 = (base64: string): string => {
  return base64.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '');
};

export const generateBanner = async (
  referenceImage: string,
  productImages: string[],
  userPrompt: string,
  style: DesignStyle,
  settings: GenerationSettings
): Promise<string> => {
  try {
    const cleanRef = cleanBase64(referenceImage);
    const cleanProducts = productImages.map(img => cleanBase64(img));

    // Construct a prompt that guides the model
    const promptText = `
      Task: Create a professional advertisement banner.

      Inputs:
      1. First Image provided is the REFERENCE STYLE.
      2. The subsequent images are the PRODUCT ASSETS.

      Directives:
      - Analyze the layout, typography, color palette, and composition of the REFERENCE STYLE image.
      - Create a NEW image that mimics this exact design style.
      - IMPORTANT: Replace the main subject/object in the reference with the PRODUCT ASSETS provided.
      - If multiple product assets are provided, arrange them compositionally to fit the design.
      - Ensure the products look naturally integrated into the lighting and perspective of the new design.
      - Design Variation: Apply a "${style}" approach to this adaptation.
      ${userPrompt ? `- Additional User Instructions: ${userPrompt}` : ''}

      Output:
      - A high-quality, high-resolution image.
    `;

    const parts: any[] = [{ text: promptText }];

    // Add reference image
    parts.push({
      inlineData: {
        mimeType: 'image/jpeg',
        data: cleanRef,
      },
    });

    // Add all product images
    cleanProducts.forEach(prod => {
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: prod,
        },
      });
    });

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: parts,
      },
      config: {
        imageConfig: {
            aspectRatio: settings.aspectRatio,
            imageSize: settings.quality
        }
      }
    });

    // Parse the response to find the image
    const candidates = response.candidates;
    if (candidates && candidates.length > 0) {
      for (const part of candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React from 'react';
import { GenerationSettings } from '../types';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  settings: GenerationSettings;
  onUpdateSettings: (newSettings: GenerationSettings) => void;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  settings,
  onUpdateSettings,
}) => {
  if (!isOpen) return null;

  const handleOverlayClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) onClose();
  };

  return (
    <div 
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200"
      onClick={handleOverlayClick}
    >
      <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-gray-200 dark:border-gray-700">
        <div className="p-6 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center">
          <h2 className="text-xl font-bold text-gray-900 dark:text-white">Settings</h2>
          <button 
            onClick={onClose}
            className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200 transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="p-6 space-y-6">
          {/* Theme Toggle */}
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              Appearance
            </label>
            <div className="flex bg-gray-100 dark:bg-gray-700 p-1 rounded-lg">
              <button
                onClick={() => onUpdateSettings({ ...settings, theme: 'light' })}
                className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
                  settings.theme === 'light' 
                    ? 'bg-white text-gray-900 shadow-sm' 
                    : 'text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
                }`}
              >
                Light
              </button>
              <button
                onClick={() => onUpdateSettings({ ...settings, theme: 'dark' })}
                className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
                  settings.theme === 'dark' 
                    ? 'bg-gray-600 text-white shadow-sm' 
                    : 'text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
                }`}
              >
                Dark
              </button>
            </div>
          </div>

          {/* Number of Outputs */}
          <div>
            <div className="flex justify-between mb-2">
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                Number of Outputs
              </label>
              <span className="text-sm font-bold text-blue-600 dark:text-blue-400">{settings.quantity}</span>
            </div>
            <input
              type="range"
              min="1"
              max="5"
              step="1"
              value={settings.quantity}
              onChange={(e) => onUpdateSettings({ ...settings, quantity: parseInt(e.target.value) })}
              className="w-full h-2 bg-gray-200 dark:bg-gray-700 rounded-lg appearance-none cursor-pointer accent-blue-600"
            />
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">Adjust how many variations to generate (1-5).</p>
