            </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ImageUpload } from './components/ImageUpload';
import { MultiImageUpload } from './components/MultiImageUpload';
import { Gallery } from './components/Gallery';
import { SettingsModal } from './components/SettingsModal';
import { generateBanner } from './services/geminiService';
import { GeneratedImage, GenerationState, STYLES, GenerationSettings, DEFAULT_SETTINGS } from './types';

const App: React.FC = () => {
  const [referenceImage, setReferenceImage] = useState<string | null>(null);
  const [productImages, setProductImages] = useState<string[]>([]);
  const [prompt, setPrompt] = useState<string>('');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState<GenerationSettings>(DEFAULT_SETTINGS);

  const [state, setState] = useState<GenerationState>({
    isGenerating: false,
    error: null,
    results: []
  });

  // Apply dark mode class to html element
  useEffect(() => {
    if (settings.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [settings.theme]);

  const handleGenerate = async () => {
    if (!referenceImage || productImages.length === 0) {
      setState(prev => ({ ...prev, error: 'Please upload both a reference image and at least one product asset.' }));
      return;
    }

    setState({
      isGenerating: true,
      error: null,
      results: []
    });

    try {
      // Determine how many images to generate based on settings.quantity
      // We cycle through the styles if quantity > styles.length, or just take first N styles.
      // If quantity is small, pick first N. If large, repeat.

      const tasks = [];
      for (let i = 0; i < settings.quantity; i++) {
        const style = STYLES[i % STYLES.length];
        tasks.push(async () => {
             // Generate
             const resultBase64 = await generateBanner(
                referenceImage,
                productImages,
                prompt,
                style,
                settings
              );
              return {
                  id: crypto.randomUUID(),
                  url: resultBase64,
                  style: style
              } as GeneratedImage;
        });
      }

      // Execute tasks
      // We can run them in parallel but might hit rate limits. 
      // With Gemini 1.5/2.0/3.0, parallel is usually fine for small batches.

      // We'll wrap them to update state individually
      const promises = tasks.map(async (task) => {
          try {
              const img = await task();
              setState(prev => ({
                ...prev,
                results: [...prev.results, img]
              }));
          } catch (err) {
              console.error("Generation failed for task", err);
          }
      });

      await Promise.all(promises);

    } catch (error: any) {
      setState(prev => ({ 
        ...prev, 
        error: error.message || 'An unexpected error occurred during generation.' 
      }));
    } finally {
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  return (
    <div className={`min-h-screen bg-gray-50 dark:bg-gradient-to-br dark:from-gray-900 dark:via-gray-800 dark:to-black text-gray-900 dark:text-white transition-colors duration-300`}>
