          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white dark:bg-gray-800/50 backdrop-blur-sm p-6 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-xl transition-colors">
              <h2 className="text-xl font-bold mb-4 text-gray-900 dark:text-white flex items-center gap-2">
                <span className="bg-blue-600 dark:bg-blue-500 text-white rounded-full w-6 h-6 flex items-center justify-center text-xs">1</span>
                Upload Assets
              </h2>

              <div className="space-y-6">
                <ImageUpload
                  label="Reference Design"
                  description="Upload a Pinterest pin or banner style"
                  image={referenceImage}
                  onImageChange={setReferenceImage}
