import { GoogleGenAI } from "@google/genai";
import { DesignStyle, GenerationSettings } from "../types";

const MODEL_NAME = 'gemini-3-pro-image-preview';

/**
 * Clean base64 string to remove data URI prefix if present.
 */
const cleanBase64 = (base64: string): string => {
  return base64.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '');
};

export const generateBanner = async (
  referenceImages: string[],
  productImages: string[],
  brandDescription: string,
  userPrompt: string,
  style: DesignStyle,
  settings: GenerationSettings
): Promise<string> => {
  try {
    // Initialize the client inside the function to ensure it uses the current process.env.API_KEY
    // which might have been updated by the API key selection dialog.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const cleanRefs = referenceImages.map(img => cleanBase64(img));
    const cleanProducts = productImages.map(img => cleanBase64(img));

    // Construct a prompt that guides the model
    const promptText = `
      Task: Create a professional advertisement banner.

      Inputs:
      1. The first ${cleanRefs.length} images provided are the REFERENCE STYLES.
      2. The subsequent images are the PRODUCT ASSETS.

      Directives:
      - Analyze the layout, typography, color palette, and composition of the REFERENCE STYLE images.
      - Create a NEW image that mimics this exact design style.
      - IMPORTANT: Replace the main subject/object in the reference with the PRODUCT ASSETS provided.
      - If multiple product assets are provided, arrange them compositionally to fit the design.
      - Ensure the products look naturally integrated into the lighting and perspective of the new design.

      Design Specifics:
      - Design Style: Apply a "${style}" approach.
      ${brandDescription ? `- Brand Identity & Guidelines: ${brandDescription}` : ''}
      ${userPrompt ? `- Custom Instructions: ${userPrompt}` : ''}

      Output:
      - A high-quality, high-resolution image.
    `;

    const parts: any[] = [{ text: promptText }];

    // Add all reference images
    cleanRefs.forEach(ref => {
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: ref,
        },
      });
    });

    // Add all product images
    cleanProducts.forEach(prod => {
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: prod,
        },
      });
    });

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: parts,
      },
      config: {
        imageConfig: {
            aspectRatio: settings.aspectRatio,
            imageSize: settings.quality
        }
      }
    });

    // Parse the response to find the image
    const candidates = response.candidates;
    if (candidates && candidates.length > 0) {
      for (const part of candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image data found in response");
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    // Rethrow with a user-friendly message if it's a permission error
    if (error.status === 'PERMISSION_DENIED' || error.code === 403) {
        throw new Error("Permission Denied: Please select a paid API Key with access to Gemini 3 Pro models.");
    }
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { MultiImageUpload } from './components/MultiImageUpload';
import { Gallery } from './components/Gallery';
