import React, { useState, useEffect } from 'react';
import { MultiImageUpload } from './components/MultiImageUpload';
import { Gallery } from './components/Gallery';
import { generateBanner } from './services/geminiService';
import { GeneratedImage, GenerationState, STYLES, GenerationSettings, DEFAULT_SETTINGS } from './types';

const App: React.FC = () => {
  const [referenceImages, setReferenceImages] = useState<string[]>([]);
  const [productImages, setProductImages] = useState<string[]>([]);

  // New input states
  const [brandDescription, setBrandDescription] = useState<string>('');
  const [prompt, setPrompt] = useState<string>('');

  const [settings, setSettings] = useState<GenerationSettings>(DEFAULT_SETTINGS);

  const [state, setState] = useState<GenerationState>({
    isGenerating: false,
    error: null,
    results: []
  });

  // API Key Selection State
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [isCheckingKey, setIsCheckingKey] = useState<boolean>(true);

  // Check for API Key on mount
  useEffect(() => {
    const checkKey = async () => {
      try {
        const win = window as any;
        if (win.aistudio?.hasSelectedApiKey) {
          const hasKey = await win.aistudio.hasSelectedApiKey();
          setHasApiKey(hasKey);
        } else {
          setHasApiKey(true);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
        setHasApiKey(true);
      } finally {
        setIsCheckingKey(false);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    const win = window as any;
    if (win.aistudio?.openSelectKey) {
      await win.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  useEffect(() => {
    if (settings.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [settings.theme]);

  const toggleTheme = () => {
    setSettings(prev => ({ ...prev, theme: prev.theme === 'dark' ? 'light' : 'dark' }));
  };

  const handleGenerate = async () => {
    if (referenceImages.length === 0 || productImages.length === 0) {
      setState(prev => ({ ...prev, error: 'Vui lòng tải lên ít nhất một mẫu thiết kế tham khảo và một hình ảnh sản phẩm.' }));
      return;
    }

    setState({
      isGenerating: true,
      error: null,
      results: []
    });

    try {
      const tasks = [];
      for (let i = 0; i < settings.quantity; i++) {
        const style = STYLES[i % STYLES.length];
        tasks.push(async () => {
             const resultBase64 = await generateBanner(
                referenceImages,
                productImages,
                brandDescription,
                prompt,
                style,
                settings
              );
              return {
                  id: crypto.randomUUID(),
                  url: resultBase64,
                  style: style
              } as GeneratedImage;
        });
      }

      const promises = tasks.map(async (task) => {
          try {
              const img = await task();
              setState(prev => ({
                ...prev,
                results: [...prev.results, img]
              }));
          } catch (err: any) {
              console.error("Generation failed for task", err);
              if (err.message && (err.message.includes("Permission Denied") || err.message.includes("403") || err.message.includes("Requested entity was not found"))) {
                 setHasApiKey(false);
                 throw new Error("Quyền truy cập bị từ chối. Vui lòng chọn một khóa API trả phí hợp lệ.");
              }
              throw err;
          }
      });

      await Promise.all(promises);

    } catch (error: any) {
      setState(prev => ({ 
        ...prev, 
        error: error.message || 'Đã xảy ra lỗi không mong muốn trong quá trình tạo.' 
      }));
    } finally {
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  // Loading Screen
  if (isCheckingKey) {
    return (
        <div className="min-h-screen bg-gray-900 flex items-center justify-center">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
        </div>
    );
  }

  // API Key Selection Screen
  if (!hasApiKey) {
      return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-white flex flex-col items-center justify-center p-4 transition-colors duration-300">
