import { db, storage } from "./firebaseConfig";
import { collection, addDoc, query, where, orderBy, getDocs, Timestamp } from "firebase/firestore";
import { ref, uploadString, getDownloadURL } from "firebase/storage";
import { GeneratedImage } from "../types";

/**
 * Uploads a base64 image to Firebase Storage and returns the public URL.
 */
const uploadImageToStorage = async (userId: string, imageBase64: string, type: 'generated' | 'reference'): Promise<string> => {
  // Create a unique filename
  const filename = `${type}_${Date.now()}_${Math.random().toString(36).substring(7)}.png`;
  const storageRef = ref(storage, `users/${userId}/${type}/${filename}`);

  // Upload the base64 string
  await uploadString(storageRef, imageBase64, 'data_url');

  // Get download URL
  return await getDownloadURL(storageRef);
};

/**
 * Saves a generated banner to Firestore linked to the user.
 */
export const saveGeneratedBannerToHistory = async (
  userId: string, 
  generatedImage: GeneratedImage,
  metadata: { prompt: string; style: string }
) => {
  try {
    // 1. Upload the image to Storage (so we don't bloat Firestore with base64)
    const imageUrl = await uploadImageToStorage(userId, generatedImage.url, 'generated');

    // 2. Save metadata to Firestore
    await addDoc(collection(db, "history"), {
      userId: userId,
      imageUrl: imageUrl,
      style: generatedImage.style,
      prompt: metadata.prompt,
      createdAt: Timestamp.now(),
      localId: generatedImage.id // Keep local ID for reference if needed
    });

    return imageUrl; // Return new cloud URL
  } catch (error) {
    console.error("Error saving to history:", error);
    throw error;
  }
};

/**
 * Fetches user's generation history.
 */
export const getUserHistory = async (userId: string): Promise<GeneratedImage[]> => {
  try {
    const q = query(
      collection(db, "history"),
      where("userId", "==", userId),
      orderBy("createdAt", "desc")
    );

    const querySnapshot = await getDocs(q);
    const history: GeneratedImage[] = [];

    querySnapshot.forEach((doc) => {
      const data = doc.data();
      history.push({
        id: doc.id,
        url: data.imageUrl,
        style: data.style
      });
    });

    return history;
  } catch (error) {
    console.error("Error fetching history:", error);
    return [];
  }
};

import React, { useState, useEffect } from 'react';
import { auth } from '../services/firebaseConfig';
import { signInWithPopup, GoogleAuthProvider, signOut, User } from 'firebase/auth';

interface AuthProps {
  onUserChange: (user: User | null) => void;
}

export const Auth: React.FC<AuthProps> = ({ onUserChange }) => {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      onUserChange(currentUser);
    });
    return () => unsubscribe();
  }, [onUserChange]);

  const handleLogin = async () => {
    const provider = new GoogleAuthProvider();
    try {
      await signInWithPopup(auth, provider);
    } catch (error) {
      console.error("Login failed:", error);
      alert("Đăng nhập thất bại. Vui lòng kiểm tra cấu hình Firebase.");
    }
  };

  const handleLogout = async () => {
    try {
      await signOut(auth);
    } catch (error) {
      console.error("Logout failed:", error);
    }
  };

  if (user) {
    return (
      <div className="flex items-center gap-3">
        <div className="hidden md:flex flex-col items-end">
          <span className="text-xs font-bold text-gray-700 dark:text-gray-200">{user.displayName}</span>
          <span className="text-[10px] text-gray-500">{user.email}</span>
        </div>
        <img 
          src={user.photoURL || ''} 
          alt="Avatar" 
          className="w-8 h-8 rounded-full border border-gray-300 dark:border-gray-600"
        />
        <button 
          onClick={handleLogout}
          className="text-xs bg-gray-200 dark:bg-gray-700 hover:bg-red-500 hover:text-white px-3 py-1.5 rounded-lg transition-colors"
        >
          Đăng xuất
        </button>
      </div>
    );
  }

  return (
    <button 
      onClick={handleLogin}
      className="flex items-center gap-2 bg-white dark:bg-gray-800 text-gray-700 dark:text-white border border-gray-300 dark:border-gray-600 px-4 py-2 rounded-lg text-sm font-bold hover:bg-gray-50 dark:hover:bg-gray-700 transition-all shadow-sm"
    >
      <svg className="w-4 h-4" viewBox="0 0 24 24">
        <path fill="currentColor" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
        <path fill="currentColor" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
        <path fill="currentColor" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.84z" />
        <path fill="currentColor" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
