};

import React, { useState, useEffect } from 'react';
import { MultiImageUpload } from './components/MultiImageUpload';
import { Gallery } from './components/Gallery';
import { Auth } from './components/Auth';
import { generateBanner } from './services/geminiService';
import { saveGeneratedBannerToHistory, getUserHistory } from './services/historyService';
import { GeneratedImage, GenerationState, STYLES, GenerationSettings, DEFAULT_SETTINGS } from './types';
import { User } from 'firebase/auth';

const App: React.FC = () => {
  const [referenceImages, setReferenceImages] = useState<string[]>([]);
  const [productImages, setProductImages] = useState<string[]>([]);

  // Input states
  const [brandDescription, setBrandDescription] = useState<string>('');
  const [prompt, setPrompt] = useState<string>('');

  const [settings, setSettings] = useState<GenerationSettings>(DEFAULT_SETTINGS);

  const [state, setState] = useState<GenerationState>({
    isGenerating: false,
    error: null,
    results: []
  });

  // User & History State
  const [user, setUser] = useState<User | null>(null);
  const [viewMode, setViewMode] = useState<'current' | 'history'>('current');
  const [historyImages, setHistoryImages] = useState<GeneratedImage[]>([]);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);

  // API Key Selection State
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [isCheckingKey, setIsCheckingKey] = useState<boolean>(true);

  // Check for API Key on mount
  useEffect(() => {
    const checkKey = async () => {
      try {
        const win = window as any;
        if (win.aistudio?.hasSelectedApiKey) {
          const hasKey = await win.aistudio.hasSelectedApiKey();
          setHasApiKey(hasKey);
        } else {
          setHasApiKey(true);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
        setHasApiKey(true);
      } finally {
        setIsCheckingKey(false);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    const win = window as any;
    if (win.aistudio?.openSelectKey) {
      await win.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  useEffect(() => {
    if (settings.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [settings.theme]);

  // Load history when user logs in or switches to history tab
  useEffect(() => {
    if (user && viewMode === 'history') {
      const fetchHistory = async () => {
        setIsLoadingHistory(true);
        const history = await getUserHistory(user.uid);
        setHistoryImages(history);
        setIsLoadingHistory(false);
      };
      fetchHistory();
    }
  }, [user, viewMode]);

  const toggleTheme = () => {
    setSettings(prev => ({ ...prev, theme: prev.theme === 'dark' ? 'light' : 'dark' }));
  };

  const handleGenerate = async () => {
    if (referenceImages.length === 0 || productImages.length === 0) {
      setState(prev => ({ ...prev, error: 'Vui lòng tải lên ít nhất một mẫu thiết kế tham khảo và một hình ảnh sản phẩm.' }));
      return;
    }

    // Switch to current view to see results
    setViewMode('current');

    setState({
      isGenerating: true,
      error: null,
      results: []
    });

    try {
      const tasks = [];
      for (let i = 0; i < settings.quantity; i++) {
        const style = STYLES[i % STYLES.length];
        tasks.push(async () => {
             const resultBase64 = await generateBanner(
                referenceImages,
                productImages,
                brandDescription,
                prompt,
                style,
                settings
              );

              const imgData: GeneratedImage = {
                  id: crypto.randomUUID(),
                  url: resultBase64,
                  style: style
              };

              // Automatically save to cloud if user is logged in
              if (user) {
                  try {
                      // Fire and forget - don't block UI for upload
                      saveGeneratedBannerToHistory(user.uid, imgData, { prompt, style });
                  } catch (e) {
                      console.error("Failed to auto-save to history", e);
                  }
              }

              return imgData;
        });
      }

      const promises = tasks.map(async (task) => {
          try {
              const img = await task();
              setState(prev => ({
                ...prev,
                results: [...prev.results, img]
              }));
          } catch (err: any) {
              console.error("Generation failed for task", err);
              if (err.message && (err.message.includes("Permission Denied") || err.message.includes("403") || err.message.includes("Requested entity was not found"))) {
                 setHasApiKey(false);
                 throw new Error("Quyền truy cập bị từ chối. Vui lòng chọn một khóa API trả phí hợp lệ.");
              }
              throw err;
          }
      });

      await Promise.all(promises);

    } catch (error: any) {
      setState(prev => ({ 
        ...prev, 
        error: error.message || 'Đã xảy ra lỗi không mong muốn trong quá trình tạo.' 
      }));
    } finally {
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  // Loading Screen
  if (isCheckingKey) {
    return (
        <div className="min-h-screen bg-gray-900 flex items-center justify-center">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
        </div>
    );
  }

  // API Key Selection Screen
  if (!hasApiKey) {
      return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-white flex flex-col items-center justify-center p-4 transition-colors duration-300">
            <div className="max-w-md w-full text-center space-y-8 bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-200 dark:border-gray-700">
                <div>
                    <h1 className="text-3xl font-extrabold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 dark:from-blue-400 dark:to-purple-500 mb-2">
                        BannerClone AI
                    </h1>
                    <p className="text-gray-600 dark:text-gray-400">
                        Tạo thiết kế banner chuyên nghiệp
                    </p>
                </div>

                <div className="py-4">
                    <p className="text-lg font-medium mb-2">Yêu cầu khóa API</p>
                    <p className="text-gray-500 dark:text-gray-400 text-sm mb-6">
                        Để sử dụng mô hình <strong>Gemini 3 Pro</strong>, bạn cần chọn khóa API từ dự án Google Cloud có trả phí.
                    </p>

                    <button
                        onClick={handleSelectKey}
                        className="w-full py-3 px-6 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-lg transform transition-all hover:scale-[1.02] active:scale-95"
                    >
                        Chọn Khóa API Trả phí
                    </button>
                </div>
            </div>
        </div>
      );
  }

  return (
    <div className={`flex h-screen overflow-hidden bg-gray-50 dark:bg-[#0f1115] text-gray-900 dark:text-white transition-colors duration-300`}>

        {/* Left Column: Results/History Area */}
        <div className="flex-1 h-full overflow-hidden flex flex-col p-6 lg:p-8">
            <header className="mb-6 flex justify-between items-center">
               <div className="flex items-center gap-3">
                  <div className="bg-gradient-to-r from-blue-600 to-purple-600 w-10 h-10 rounded-xl flex items-center justify-center shadow-lg">
                      <span className="text-white font-bold text-xl">B</span>
                  </div>
                  <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 dark:from-blue-400 dark:to-purple-500">
                    BannerClone AI
                  </h1>
               </div>

               <div className="flex items-center gap-4">
                 {/* View Mode Toggle */}
                 {user && (
                   <div className="flex bg-gray-100 dark:bg-gray-800 rounded-lg p-1">
                      <button 
                        onClick={() => setViewMode('current')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${viewMode === 'current' ? 'bg-white dark:bg-gray-700 shadow-sm' : 'text-gray-500'}`}
                      >
                        Hiện tại
                      </button>
                      <button 
                        onClick={() => setViewMode('history')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${viewMode === 'history' ? 'bg-white dark:bg-gray-700 shadow-sm' : 'text-gray-500'}`}
                      >
                        Lịch sử
                      </button>
                   </div>
                 )}

                 <Auth onUserChange={setUser} />

                  <button 
                      onClick={toggleTheme}
                      className="p-2 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-all"
                      title={settings.theme === 'dark' ? "Chuyển sang chế độ Sáng" : "Chuyển sang chế độ Tối"}
                  >
                      {settings.theme === 'dark' ? (
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M12 3v2.25m6.364.386l-1.591 1.591M21 12h-2.25m-.386 6.364l-1.591-1.591M12 18.75V21m-4.773-4.227l-1.591 1.591M5.25 12H3m4.227-4.773L5.636 5.636M15.75 12a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0z" />
                      </svg>
                      ) : (
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M21.752 15.002A9.718 9.718 0 0118 15.75c-5.385 0-9.75-4.365-9.75-9.75 0-1.33.266-2.597.748-3.752A9.753 9.753 0 003 11.25C3 16.635 7.365 21 12.75 21a9.753 9.753 0 009.002-5.998z" />
                      </svg>
                      )}
                  </button>
               </div>
            </header>

            {viewMode === 'current' ? (
                <Gallery 
                    images={state.results} 
                    isGenerating={state.isGenerating} 
                    expectedCount={settings.quantity}
                />
            ) : (
                <div className="h-full flex flex-col">
                  <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    Lịch sử thiết kế của bạn
                  </h2>
                  {isLoadingHistory ? (
                     <div className="flex-1 flex items-center justify-center">
                        <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-blue-500"></div>
                     </div>
                  ) : (
                    <Gallery 
                        images={historyImages} 
                        isGenerating={false} 
                        expectedCount={0}
                    />
                  )}
                </div>
            )}
        </div>

        {/* Right Column: Sidebar (Inputs & Settings) */}
        <div className="w-full lg:w-[420px] bg-white dark:bg-[#1a1d24] h-full overflow-y-auto border-l border-gray-200 dark:border-gray-800 shadow-2xl flex flex-col z-20 custom-scrollbar">
            <div className="p-6 space-y-8">
                {/* Notice if not logged in */}
                {!user && (
                  <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 p-4 rounded-xl flex gap-3 items-start">
                    <svg className="w-5 h-5 text-blue-500 mt-0.5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    <p className="text-xs text-blue-800 dark:text-blue-200">
                      <strong>Mẹo:</strong> Đăng nhập để tự động lưu lại tất cả các thiết kế bạn tạo ra và xem lại chúng bất cứ lúc nào.
                    </p>
                  </div>
                )}

                {/* Upload Section */}
                <div className="space-y-6">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-gray-800 pb-2">
                         <span className="bg-blue-100 dark:bg-blue-900/50 text-blue-600 dark:text-blue-400 rounded-lg p-1">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                 <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" />
                             </svg>
                         </span>
                        Tài nguyên
                    </h2>
                    <MultiImageUpload
                        label="Mẫu thiết kế (Reference)"
                        description="Tải lên mẫu banner bạn muốn học theo"
                        images={referenceImages}
                        onImagesChange={setReferenceImages}
                    />
                    <MultiImageUpload
                        label="Sản phẩm (Assets)"
                        description="Tải lên ảnh sản phẩm cần ghép"
                        images={productImages}
                        onImagesChange={setProductImages}
                    />
                </div>

                {/* Prompt Section */}
                <div className="space-y-5">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-gray-800 pb-2">
                        <span className="bg-purple-100 dark:bg-purple-900/50 text-purple-600 dark:text-purple-400 rounded-lg p-1">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                 <path strokeLinecap="round" strokeLinejoin="round" d="M16.862 4.487l1.687-1.688a1.875 1.875 0 112.652 2.652L10.582 16.07a4.5 4.5 0 01-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 011.13-1.897l8.932-8.931zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0115.75 21H5.25A2.25 2.25 0 013 18.75V8.25A2.25 2.25 0 015.25 6H10" />
                             </svg>
                         </span>
                        Thông tin & Yêu cầu
                    </h2>

                    <div>
                        <label htmlFor="brandDescription" className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-2 uppercase">
                            Mô tả thương hiệu
                        </label>
                        <textarea
                            id="brandDescription"
                            rows={2}
                            className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-xl p-3 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all resize-none text-sm"
                            placeholder="Ví dụ: Thương hiệu thời trang cao cấp, tối giản..."
                            value={brandDescription}
                            onChange={(e) => setBrandDescription(e.target.value)}
                        />
                    </div>

                    <div>
                        <label htmlFor="prompt" className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-2 uppercase">
                            Yêu cầu tùy chỉnh
                        </label>
                        <textarea
                            id="prompt"
                            rows={3}
                            className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-xl p-3 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all resize-none text-sm"
                            placeholder="Ví dụ: Đổi nền sang màu xanh biển, thêm chữ 'Giảm giá mùa hè'..."
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                        />
                    </div>
                </div>

                {/* Settings Section */}
                <div className="space-y-5">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-gray-800 pb-2">
                        <span className="bg-green-100 dark:bg-green-900/50 text-green-600 dark:text-green-400 rounded-lg p-1">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                 <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 6h9.75M10.5 6a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 10-3 0M3.75 6H7.5m3 12h9.75m-9.75 0a1.5 1.5 0 01-3 0m3 0a1.5 1.5 0 00-3 0m-3.75 0H7.5m9-6h3.75m-3.75 0a1.5 1.5 0 01-3 0m3 0a1.5 1.5 0 00-3 0m-9.75 0h9.75" />
                             </svg>
                         </span>
                        Cấu hình
                    </h2>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                             <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-1">Tỷ lệ khung hình</label>
                             <select
                                 value={settings.aspectRatio}
                                 onChange={(e) => setSettings({ ...settings, aspectRatio: e.target.value as any })}
                                 className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 text-gray-900 dark:text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
                             >
                                 <option value="1:1">1:1 (Vuông)</option>
                                 <option value="3:4">3:4 (Dọc)</option>
                                 <option value="4:3">4:3 (Ngang)</option>
                                 <option value="9:16">9:16 (Story)</option>
                                 <option value="16:9">16:9 (Wide)</option>
                             </select>
                         </div>
                         <div>
                             <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-1">Chất lượng</label>
                             <select
                                 value={settings.quality}
                                 onChange={(e) => setSettings({ ...settings, quality: e.target.value as any })}
                                 className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 text-gray-900 dark:text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
                             >
                                 <option value="1K">Tiêu chuẩn (1K)</option>
                                 <option value="2K">Cao (2K)</option>
                                 <option value="4K">Siêu cao (4K)</option>
                             </select>
                          </div>
                    </div>

                    <div className="bg-gray-50 dark:bg-gray-900 rounded-lg p-3 border border-gray-200 dark:border-gray-700">
                        <div className="flex justify-between mb-2">
                            <label className="text-xs font-bold text-gray-500 dark:text-gray-400">Số lượng biến thể</label>
                            <span className="text-xs font-bold text-blue-600 dark:text-blue-400">{settings.quantity}</span>
                        </div>
                        <input
                            type="range"
                            min="1"
                            max="5"
                            step="1"
                            value={settings.quantity}
                            onChange={(e) => setSettings({ ...settings, quantity: parseInt(e.target.value) })}
                            className="w-full h-1.5 bg-gray-300 dark:bg-gray-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                        />
                    </div>
                </div>

                {/* Error Message */}
                {state.error && (
                    <div className="p-3 bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 rounded-lg text-red-800 dark:text-red-300 text-xs">
                        {state.error}
                    </div>
                )}
            </div>

            {/* Footer / Generate Action */}
            <div className="mt-auto p-6 border-t border-gray-200 dark:border-gray-800 bg-white dark:bg-[#1a1d24] sticky bottom-0 z-10">
                <button
                    onClick={handleGenerate}
                    disabled={state.isGenerating || referenceImages.length === 0 || productImages.length === 0}
                    className={`w-full py-4 px-6 rounded-xl font-bold text-lg shadow-xl transition-all duration-300 flex items-center justify-center gap-3
                    ${state.isGenerating || referenceImages.length === 0 || productImages.length === 0
                        ? 'bg-gray-200 dark:bg-gray-800 text-gray-400 dark:text-gray-500 cursor-not-allowed'
                        : 'bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white transform hover:scale-[1.02] hover:shadow-blue-500/25'
                    }`}
                >
                    {state.isGenerating ? (
                        <>
                            <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                            </svg>
                            Đang tạo...
                        </>
                    ) : (
                        <>
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09z" />
                            </svg>
                            Tạo thiết kế
                        </>
                    )}
                </button>
            </div>
        </div>
    </div>
  );
};

export default App;

import firebase from "firebase/app";
import "firebase/auth";
import "firebase/firestore";
import "firebase/storage";

// Firebase configuration using environment variables
const firebaseConfig = {
  apiKey: process.env.FIREBASE_API_KEY,
  authDomain: process.env.FIREBASE_AUTH_DOMAIN,
  projectId: process.env.FIREBASE_PROJECT_ID,
  storageBucket: process.env.FIREBASE_STORAGE_BUCKET,
  messagingSenderId: process.env.FIREBASE_MESSAGING_SENDER_ID,
  appId: process.env.FIREBASE_APP_ID,
  measurementId: process.env.FIREBASE_MEASUREMENT_ID
};

// Initialize Firebase
if (!firebase.apps.length) {
    firebase.initializeApp(firebaseConfig);
}

const app = firebase.app();

// Initialize Services
export const auth = firebase.auth();
export const db = firebase.firestore();
export const storage = firebase.storage();

export default app;

import React, { useState, useEffect } from 'react';
import { MultiImageUpload } from './components/MultiImageUpload';
import { Gallery } from './components/Gallery';
import { Auth } from './components/Auth';
import { generateBanner } from './services/geminiService';
import { saveGeneratedBannerToHistory, getUserHistory } from './services/historyService';
import { GeneratedImage, GenerationState, STYLES, GenerationSettings, DEFAULT_SETTINGS } from './types';
import firebase from 'firebase/app';

const App: React.FC = () => {
  const [referenceImages, setReferenceImages] = useState<string[]>([]);
  const [productImages, setProductImages] = useState<string[]>([]);

  // Input states
  const [brandDescription, setBrandDescription] = useState<string>('');
  const [prompt, setPrompt] = useState<string>('');

  const [settings, setSettings] = useState<GenerationSettings>(DEFAULT_SETTINGS);

  const [state, setState] = useState<GenerationState>({
    isGenerating: false,
    error: null,
    results: []
  });

  // User & History State
  const [user, setUser] = useState<firebase.User | null>(null);
  const [viewMode, setViewMode] = useState<'current' | 'history'>('current');
  const [historyImages, setHistoryImages] = useState<GeneratedImage[]>([]);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);

  // API Key Selection State
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [isCheckingKey, setIsCheckingKey] = useState<boolean>(true);

  // Check for API Key on mount
  useEffect(() => {
    const checkKey = async () => {
      try {
        const win = window as any;
        if (win.aistudio?.hasSelectedApiKey) {
          const hasKey = await win.aistudio.hasSelectedApiKey();
          setHasApiKey(hasKey);
        } else {
          setHasApiKey(true);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
        setHasApiKey(true);
      } finally {
        setIsCheckingKey(false);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    const win = window as any;
    if (win.aistudio?.openSelectKey) {
      await win.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  useEffect(() => {
    if (settings.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [settings.theme]);

  // Load history when user logs in or switches to history tab
  useEffect(() => {
    if (user && viewMode === 'history') {
      const fetchHistory = async () => {
        setIsLoadingHistory(true);
        const history = await getUserHistory(user.uid);
        setHistoryImages(history);
        setIsLoadingHistory(false);
      };
      fetchHistory();
    }
  }, [user, viewMode]);

  const toggleTheme = () => {
    setSettings(prev => ({ ...prev, theme: prev.theme === 'dark' ? 'light' : 'dark' }));
  };

  const handleGenerate = async () => {
    if (referenceImages.length === 0 || productImages.length === 0) {
      setState(prev => ({ ...prev, error: 'Vui lòng tải lên ít nhất một mẫu thiết kế tham khảo và một hình ảnh sản phẩm.' }));
      return;
    }

    // Switch to current view to see results
    setViewMode('current');

    setState({
      isGenerating: true,
      error: null,
      results: []
    });

    try {
      const tasks = [];
      for (let i = 0; i < settings.quantity; i++) {
        const style = STYLES[i % STYLES.length];
        tasks.push(async () => {
             const resultBase64 = await generateBanner(
                referenceImages,
                productImages,
                brandDescription,
                prompt,
                style,
                settings
              );

              const imgData: GeneratedImage = {
                  id: crypto.randomUUID(),
                  url: resultBase64,
                  style: style
              };

              // Automatically save to cloud if user is logged in
              if (user) {
                  try {
                      // Fire and forget - don't block UI for upload
                      saveGeneratedBannerToHistory(user.uid, imgData, { prompt, style });
                  } catch (e) {
                      console.error("Failed to auto-save to history", e);
                  }
              }

              return imgData;
        });
      }

      const promises = tasks.map(async (task) => {
          try {
              const img = await task();
              setState(prev => ({
                ...prev,
                results: [...prev.results, img]
              }));
          } catch (err: any) {
              console.error("Generation failed for task", err);
              if (err.message && (err.message.includes("Permission Denied") || err.message.includes("403") || err.message.includes("Requested entity was not found"))) {
                 setHasApiKey(false);
                 throw new Error("Quyền truy cập bị từ chối. Vui lòng chọn một khóa API trả phí hợp lệ.");
              }
              throw err;
          }
      });

      await Promise.all(promises);

    } catch (error: any) {
      setState(prev => ({ 
        ...prev, 
        error: error.message || 'Đã xảy ra lỗi không mong muốn trong quá trình tạo.' 
      }));
    } finally {
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  // Loading Screen
  if (isCheckingKey) {
    return (
        <div className="min-h-screen bg-gray-900 flex items-center justify-center">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
        </div>
    );
  }

  // API Key Selection Screen
  if (!hasApiKey) {
      return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-white flex flex-col items-center justify-center p-4 transition-colors duration-300">
            <div className="max-w-md w-full text-center space-y-8 bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-200 dark:border-gray-700">
                <div>
                    <h1 className="text-3xl font-extrabold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 dark:from-blue-400 dark:to-purple-500 mb-2">
                        BannerClone AI
                    </h1>
                    <p className="text-gray-600 dark:text-gray-400">
                        Tạo thiết kế banner chuyên nghiệp
                    </p>
                </div>

                <div className="py-4">
                    <p className="text-lg font-medium mb-2">Yêu cầu khóa API</p>
                    <p className="text-gray-500 dark:text-gray-400 text-sm mb-6">
                        Để sử dụng mô hình <strong>Gemini 3 Pro</strong>, bạn cần chọn khóa API từ dự án Google Cloud có trả phí.
                    </p>

                    <button
                        onClick={handleSelectKey}
                        className="w-full py-3 px-6 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-lg transform transition-all hover:scale-[1.02] active:scale-95"
                    >
                        Chọn Khóa API Trả phí
                    </button>
                </div>
            </div>
        </div>
      );
  }

  return (
    <div className={`flex h-screen overflow-hidden bg-gray-50 dark:bg-[#0f1115] text-gray-900 dark:text-white transition-colors duration-300`}>

        {/* Left Column: Results/History Area */}
        <div className="flex-1 h-full overflow-hidden flex flex-col p-6 lg:p-8">
            <header className="mb-6 flex justify-between items-center">
               <div className="flex items-center gap-3">
                  <div className="bg-gradient-to-r from-blue-600 to-purple-600 w-10 h-10 rounded-xl flex items-center justify-center shadow-lg">
                      <span className="text-white font-bold text-xl">B</span>
                  </div>
                  <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 dark:from-blue-400 dark:to-purple-500">
                    BannerClone AI
                  </h1>
               </div>

               <div className="flex items-center gap-4">
                 {/* View Mode Toggle */}
                 {user && (
                   <div className="flex bg-gray-100 dark:bg-gray-800 rounded-lg p-1">
                      <button 
                        onClick={() => setViewMode('current')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${viewMode === 'current' ? 'bg-white dark:bg-gray-700 shadow-sm' : 'text-gray-500'}`}
                      >
                        Hiện tại
                      </button>
                      <button 
                        onClick={() => setViewMode('history')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${viewMode === 'history' ? 'bg-white dark:bg-gray-700 shadow-sm' : 'text-gray-500'}`}
                      >
                        Lịch sử
                      </button>
                   </div>
                 )}

                 <Auth onUserChange={setUser} />

                  <button 
                      onClick={toggleTheme}
                      className="p-2 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-all"
                      title={settings.theme === 'dark' ? "Chuyển sang chế độ Sáng" : "Chuyển sang chế độ Tối"}
                  >
                      {settings.theme === 'dark' ? (
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M12 3v2.25m6.364.386l-1.591 1.591M21 12h-2.25m-.386 6.364l-1.591-1.591M12 18.75V21m-4.773-4.227l-1.591 1.591M5.25 12H3m4.227-4.773L5.636 5.636M15.75 12a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0z" />
                      </svg>
                      ) : (
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M21.752 15.002A9.718 9.718 0 0118 15.75c-5.385 0-9.75-4.365-9.75-9.75 0-1.33.266-2.597.748-3.752A9.753 9.753 0 003 11.25C3 16.635 7.365 21 12.75 21a9.753 9.753 0 009.002-5.998z" />
                      </svg>
                      )}
                  </button>
               </div>
            </header>

            {viewMode === 'current' ? (
                <Gallery 
                    images={state.results} 
                    isGenerating={state.isGenerating} 
                    expectedCount={settings.quantity}
                />
            ) : (
                <div className="h-full flex flex-col">
                  <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    Lịch sử thiết kế của bạn
                  </h2>
                  {isLoadingHistory ? (
                     <div className="flex-1 flex items-center justify-center">
                        <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-blue-500"></div>
                     </div>
                  ) : (
                    <Gallery 
                        images={historyImages} 
                        isGenerating={false} 
                        expectedCount={0}
                    />
                  )}
                </div>
            )}
        </div>

        {/* Right Column: Sidebar (Inputs & Settings) */}
        <div className="w-full lg:w-[420px] bg-white dark:bg-[#1a1d24] h-full overflow-y-auto border-l border-gray-200 dark:border-gray-800 shadow-2xl flex flex-col z-20 custom-scrollbar">
            <div className="p-6 space-y-8">
                {/* Notice if not logged in */}
                {!user && (
                  <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 p-4 rounded-xl flex gap-3 items-start">
                    <svg className="w-5 h-5 text-blue-500 mt-0.5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    <p className="text-xs text-blue-800 dark:text-blue-200">
                      <strong>Mẹo:</strong> Đăng nhập để tự động lưu lại tất cả các thiết kế bạn tạo ra và xem lại chúng bất cứ lúc nào.
                    </p>
                  </div>
                )}

                {/* Upload Section */}
                <div className="space-y-6">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-gray-800 pb-2">
                         <span className="bg-blue-100 dark:bg-blue-900/50 text-blue-600 dark:text-blue-400 rounded-lg p-1">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                 <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" />
                             </svg>
                         </span>
                        Tài nguyên
                    </h2>
                    <MultiImageUpload
                        label="Mẫu thiết kế (Reference)"
                        description="Tải lên mẫu banner bạn muốn học theo"
                        images={referenceImages}
                        onImagesChange={setReferenceImages}
                    />
                    <MultiImageUpload
                        label="Sản phẩm (Assets)"
                        description="Tải lên ảnh sản phẩm cần ghép"
                        images={productImages}
                        onImagesChange={setProductImages}
                    />
                </div>

                {/* Prompt Section */}
                <div className="space-y-5">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-gray-800 pb-2">
                        <span className="bg-purple-100 dark:bg-purple-900/50 text-purple-600 dark:text-purple-400 rounded-lg p-1">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                 <path strokeLinecap="round" strokeLinejoin="round" d="M16.862 4.487l1.687-1.688a1.875 1.875 0 112.652 2.652L10.582 16.07a4.5 4.5 0 01-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 011.13-1.897l8.932-8.931zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0115.75 21H5.25A2.25 2.25 0 013 18.75V8.25A2.25 2.25 0 015.25 6H10" />
                             </svg>
                         </span>
                        Thông tin & Yêu cầu
                    </h2>

                    <div>
                        <label htmlFor="brandDescription" className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-2 uppercase">
                            Mô tả thương hiệu
                        </label>
                        <textarea
                            id="brandDescription"
                            rows={2}
                            className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-xl p-3 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all resize-none text-sm"
                            placeholder="Ví dụ: Thương hiệu thời trang cao cấp, tối giản..."
                            value={brandDescription}
                            onChange={(e) => setBrandDescription(e.target.value)}
                        />
                    </div>

                    <div>
                        <label htmlFor="prompt" className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-2 uppercase">
                            Yêu cầu tùy chỉnh
                        </label>
                        <textarea
                            id="prompt"
                            rows={3}
                            className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-xl p-3 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all resize-none text-sm"
                            placeholder="Ví dụ: Đổi nền sang màu xanh biển, thêm chữ 'Giảm giá mùa hè'..."
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                        />
                    </div>
                </div>

                {/* Settings Section */}
                <div className="space-y-5">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-gray-800 pb-2">
                        <span className="bg-green-100 dark:bg-green-900/50 text-green-600 dark:text-green-400 rounded-lg p-1">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                 <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 6h9.75M10.5 6a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 10-3 0M3.75 6H7.5m3 12h9.75m-9.75 0a1.5 1.5 0 01-3 0m3 0a1.5 1.5 0 00-3 0m-3.75 0H7.5m9-6h3.75m-3.75 0a1.5 1.5 0 01-3 0m3 0a1.5 1.5 0 00-3 0m-9.75 0h9.75" />
                             </svg>
                         </span>
                        Cấu hình
                    </h2>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                             <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-1">Tỷ lệ khung hình</label>
                             <select
                                 value={settings.aspectRatio}
                                 onChange={(e) => setSettings({ ...settings, aspectRatio: e.target.value as any })}
                                 className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 text-gray-900 dark:text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
                             >
                                 <option value="1:1">1:1 (Vuông)</option>
                                 <option value="3:4">3:4 (Dọc)</option>
                                 <option value="4:3">4:3 (Ngang)</option>
                                 <option value="9:16">9:16 (Story)</option>
                                 <option value="16:9">16:9 (Wide)</option>
                             </select>
                         </div>
                         <div>
                             <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-1">Chất lượng</label>
                             <select
                                 value={settings.quality}
                                 onChange={(e) => setSettings({ ...settings, quality: e.target.value as any })}
                                 className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 text-gray-900 dark:text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
                             >
                                 <option value="1K">Tiêu chuẩn (1K)</option>
                                 <option value="2K">Cao (2K)</option>
                                 <option value="4K">Siêu cao (4K)</option>
                             </select>
                          </div>
                    </div>

                    <div className="bg-gray-50 dark:bg-gray-900 rounded-lg p-3 border border-gray-200 dark:border-gray-700">
                        <div className="flex justify-between mb-2">
                            <label className="text-xs font-bold text-gray-500 dark:text-gray-400">Số lượng biến thể</label>
                            <span className="text-xs font-bold text-blue-600 dark:text-blue-400">{settings.quantity}</span>
                        </div>
                        <input
                            type="range"
                            min="1"
                            max="5"
                            step="1"
                            value={settings.quantity}
                            onChange={(e) => setSettings({ ...settings, quantity: parseInt(e.target.value) })}
                            className="w-full h-1.5 bg-gray-300 dark:bg-gray-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                        />
                    </div>
                </div>

                {/* Error Message */}
                {state.error && (
                    <div className="p-3 bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 rounded-lg text-red-800 dark:text-red-300 text-xs">
                        {state.error}
                    </div>
                )}
            </div>

            {/* Footer / Generate Action */}
            <div className="mt-auto p-6 border-t border-gray-200 dark:border-gray-800 bg-white dark:bg-[#1a1d24] sticky bottom-0 z-10">
                <button
                    onClick={handleGenerate}
                    disabled={state.isGenerating || referenceImages.length === 0 || productImages.length === 0}
                    className={`w-full py-4 px-6 rounded-xl font-bold text-lg shadow-xl transition-all duration-300 flex items-center justify-center gap-3
                    ${state.isGenerating || referenceImages.length === 0 || productImages.length === 0
                        ? 'bg-gray-200 dark:bg-gray-800 text-gray-400 dark:text-gray-500 cursor-not-allowed'
                        : 'bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white transform hover:scale-[1.02] hover:shadow-blue-500/25'
                    }`}
                >
                    {state.isGenerating ? (
                        <>
                            <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                            </svg>
                            Đang tạo...
                        </>
                    ) : (
                        <>
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09z" />
                            </svg>
                            Tạo thiết kế
                        </>
                    )}
                </button>
            </div>
        </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { auth } from '../services/firebaseConfig';
import firebase from 'firebase/app';

interface AuthProps {
  onUserChange: (user: firebase.User | null) => void;
}

export const Auth: React.FC<AuthProps> = ({ onUserChange }) => {
  const [user, setUser] = useState<firebase.User | null>(null);

  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      onUserChange(currentUser);
    });
    return () => unsubscribe();
  }, [onUserChange]);

  const handleLogin = async () => {
    const provider = new firebase.auth.GoogleAuthProvider();
    try {
      await auth.signInWithPopup(provider);
    } catch (error) {
      console.error("Login failed:", error);
      alert("Đăng nhập thất bại. Vui lòng kiểm tra cấu hình Firebase.");
    }
  };

  const handleLogout = async () => {
    try {
      await auth.signOut();
    } catch (error) {
      console.error("Logout failed:", error);
    }
  };

  if (user) {
    return (
      <div className="flex items-center gap-3">
        <div className="hidden md:flex flex-col items-end">
          <span className="text-xs font-bold text-gray-700 dark:text-gray-200">{user.displayName}</span>
