import { GoogleGenAI } from "@google/genai";
import { DesignStyle, GenerationSettings, TypographyStyle } from "../types";

const MODEL_NAME = 'gemini-3-pro-image-preview';

/**
 * Clean base64 string to remove data URI prefix if present.
 */
const cleanBase64 = (base64: string): string => {
  return base64.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '');
};

// Mapping Vietnamese Typography categories to detailed English Design Prompts
const TYPO_PROMPT_MAP: Record<TypographyStyle, string> = {
  'Tự động': "Analyze the visual context and choose the most suitable font style automatically.",
  'Làm đẹp, thời trang, mềm mại': "TYPOGRAPHY STYLE: Elegant, Sophisticated, and Soft. Use high-contrast Serif fonts (like Didot, Bodoni) or thin, graceful Sans-Serif. The text should feel luxurious, feminine, and editorial fashion magazine style.",
  'Cách điệu, dễ thương': "TYPOGRAPHY STYLE: Stylized, Cute, and Playful. Use Handwritten, Script, or Rounded Sans-Serif fonts. Incorporate organic curves, decorative swashes, or doodle-like elements. The vibe should be friendly and approachable.",
  'Tươi trẻ, màu sắc': "TYPOGRAPHY STYLE: Youthful, Vibrant, and Colorful. Use Bold Bubble fonts, 3D text effects, or Pop-art inspired type. The text should be dynamic, high-energy, potentially using gradients or multiple bright colors.",
  'Chuyên nghiệp, hiện đại': "TYPOGRAPHY STYLE: Professional, Corporate, and Clean. Use Geometric Sans-Serif fonts (like Helvetica, Futura, Roboto). Keep lines straight, balanced, and minimalist. Trustworthy and clear.",
  'Hoài cổ (Retro/Vintage)': "TYPOGRAPHY STYLE: Retro, Vintage, and Nostalgic. Use Cooper Black, slab serifs, or textured fonts reminiscent of the 70s, 80s, or 90s. Can include distressed edges, noise texture, or neon sign aesthetics.",
  'Mạnh mẽ, nổi bật': "TYPOGRAPHY STYLE: Bold, Impactful, and Loud. Use Heavy/Black weight Sans-Serif fonts, All-Caps. High contrast against the background. Poster-style typography designed to grab immediate attention."
};

export const generateBanner = async (
  referenceImages: string[],
  productImages: string[],
  brandDescription: string,
  promoInfo: string,
  userPrompt: string,
  style: DesignStyle,
  settings: GenerationSettings
): Promise<string> => {
  try {
    // Initialize the client inside the function to ensure it uses the current process.env.API_KEY
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const cleanRefs = referenceImages.map(img => cleanBase64(img));
    const cleanProducts = productImages.map(img => cleanBase64(img));

    // Get the specific typography instruction
    const typoInstruction = TYPO_PROMPT_MAP[settings.typography] || TYPO_PROMPT_MAP['Tự động'];

    // Determine target Aspect Ratio and Safe Zone prompting
    let targetAspectRatio = settings.aspectRatio;
    let safeZoneInstruction = "";

    if (settings.aspectRatio === 'Facebook Cover') {
        // Facebook Cover is 2048x779 (approx 2.63:1). We use 16:9 (widest supported) and instruct the model.
        targetAspectRatio = '16:9'; 
        safeZoneInstruction = `
        CRITICAL FORMAT REQUIREMENT: FACEBOOK COVER (2048x779 pixels).
        - SAFE ZONES: You MUST design with "Safe Zones" in mind.
        - Mobile View: The center 640px width is the ONLY safe area for text, logos, and main product details.
        - Desktop View: Displays the full width. The sides are visible on desktop but cropped on mobile.
        - COMPOSITION RULE: Place ALL vital text, headlines, and key product elements strictly in the CENTER of the image.
        - The left and right sides should contain extended background, abstract elements, or secondary atmosphere to fill the desktop view without being essential.
        `;
    }

    // Construct a sophisticated prompt acting as a Creative Director
    const promptText = `
      ROLE: expert AI Graphic Designer and Copywriter.
      TASK: Create a high-converting, visually stunning advertising banner.

      INPUTS:
      1. Reference Images (First ${cleanRefs.length} images): These define the visual style, layout composition, color grading, and general vibe.
      2. Product Assets (Subsequent images): These are the hero objects to feature.

      CORE DIRECTIVES:
      1. STYLE ADAPTATION (Visuals):
         - Analyze the "vibe" of the reference images.
         - Create a COMPLETELY NEW composition. Do not just copy pixels, steal the "look and feel".
         - Ensure Product Assets are naturally integrated (match lighting, shadows, reflection, perspective).

      2. INTELLIGENT COPYWRITING & TYPOGRAPHY:
         - **Typography Directive:** ${typoInstruction}
         - **Text Strategy:** ${promoInfo || brandDescription ? 'ADAPTIVE' : 'GENERATIVE'}.
         - IF user provided info ("${promoInfo}", "${brandDescription}"):
            - Select only the most impactful keywords. Do not clutter.
            - Render the text using the Typography Style defined above.
         - IF NO user info is provided:
            - Create a catchy, short tagline based on the product.
            - Example: "Cool for the Summer" for a drink.
         - **Legibility:** Text must be artistic but readable. Follow visual hierarchy (Headline > Subtext).

      3. COMPOSITION RULES:
         - Prioritize visual aesthetics. Negative space is key.
         - Design Style: Apply a "${style}" approach.
         ${safeZoneInstruction}
         ${userPrompt ? `- User's Custom Wishlist: ${userPrompt}` : ''}

      OUTPUT:
      - A single, high-quality image containing the product and rendered text.
    `;

    const parts: any[] = [{ text: promptText }];

    // Add all reference images
    cleanRefs.forEach(ref => {
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: ref,
        },
      });
    });

    // Add all product images
    cleanProducts.forEach(prod => {
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: prod,
        },
      });
    });

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: parts,
      },
      config: {
        imageConfig: {
            aspectRatio: targetAspectRatio as any,
            imageSize: settings.quality
        }
      }
    });

    // Parse the response to find the image
    const candidates = response.candidates;
    if (candidates && candidates.length > 0) {
      for (const part of candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image data found in response");
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    if (error.status === 'PERMISSION_DENIED' || error.code === 403) {
        throw new Error("Permission Denied: Please select a paid API Key with access to Gemini 3 Pro models.");
    }
    throw error;
  }
};

/**
 * Edit an existing banner based on a new prompt.
 */
export const editBanner = async (
    currentImageBase64: string,
    editPrompt: string,
    aspectRatio: string
  ): Promise<string> => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Handle Facebook Cover mapping for edits as well
      let targetAspectRatio = aspectRatio;
      if (aspectRatio === 'Facebook Cover') {
        targetAspectRatio = '16:9';
      }

      const promptText = `
        TASK: Edit the provided image based on the user's instruction.
        USER INSTRUCTION: "${editPrompt}"

        DIRECTIVES:
        - Maintain the overall high quality and resolution.
        - Only modify the elements requested by the user.
        - Ensure typography remains legible if touched.
        ${aspectRatio === 'Facebook Cover' ? '- IMPORTANT: Maintain Facebook Cover Safe Zones (Content in center, Background on sides).' : ''}
        - Return the full image.
      `;

      const response = await ai.models.generateContent({
        model: MODEL_NAME,
        contents: {
          parts: [
            { text: promptText },
            {
              inlineData: {
                mimeType: 'image/png',
                data: cleanBase64(currentImageBase64),
              },
            },
          ],
        },
        config: {
            imageConfig: {
                aspectRatio: targetAspectRatio as any, 
                imageSize: '1K' 
            }
        }
      });

      const candidates = response.candidates;
      if (candidates && candidates.length > 0) {
        for (const part of candidates[0].content.parts) {
          if (part.inlineData && part.inlineData.data) {
            return `data:image/png;base64,${part.inlineData.data}`;
          }
        }
      }

      throw new Error("No image data found in response");
    } catch (error: any) {
      console.error("Gemini Edit API Error:", error);
      if (error.status === 'PERMISSION_DENIED' || error.code === 403) {
          throw new Error("Permission Denied: Please select a paid API Key with access to Gemini 3 Pro models.");
      }
      throw error;
    }
  };

import React, { useState } from 'react';
import { GeneratedImage } from '../types';

interface GalleryProps {
  images: GeneratedImage[];
  isGenerating: boolean;
  expectedCount: number;
  onRegenerate: (id: string, prompt: string) => void;
}

// Helper to map setting string to Tailwind aspect class
const getAspectClass = (ratio: string) => {
    switch (ratio) {
        case '1:1': return 'aspect-square';
        case '3:4': return 'aspect-[3/4]';
        case '4:3': return 'aspect-[4/3]';
        case '9:16': return 'aspect-[9/16]';
        case '16:9': return 'aspect-video';
        case 'Facebook Cover': return 'aspect-[2048/779]'; // Custom aspect ratio for preview
        default: return 'aspect-[3/4]';
    }
};

export const Gallery: React.FC<GalleryProps> = ({ images, isGenerating, expectedCount, onRegenerate }) => {
  const [selectedImage, setSelectedImage] = useState<GeneratedImage | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editPrompt, setEditPrompt] = useState<string>('');

  // State for Lightbox Edit
  const [lightboxPrompt, setLightboxPrompt] = useState<string>('');
  const [isLightboxEditing, setIsLightboxEditing] = useState<boolean>(false);

  const handleEditClick = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setEditingId(id);
      setEditPrompt('');
  };

  const handleCancelEdit = (e: React.MouseEvent) => {
      e.stopPropagation();
      setEditingId(null);
  };

  const handleSubmitEdit = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      if (editPrompt.trim()) {
          onRegenerate(id, editPrompt);
          setEditingId(null);
      }
  };

  const handleLightboxRegenerate = () => {
      if (selectedImage && lightboxPrompt.trim()) {
          onRegenerate(selectedImage.id, lightboxPrompt);
          setLightboxPrompt('');
          setIsLightboxEditing(false);
          // Optionally close lightbox or keep it open to wait for result. 
          // Since result updates in bg, keeping it open might show old image until update.
          // Let's close it to show the grid loading state.
          setSelectedImage(null); 
      }
  };

  // If initial state (empty and not generating), show a welcome placeholder
  if (images.length === 0 && !isGenerating) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-center p-12 border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-3xl bg-gray-50/50 dark:bg-gray-800/30 min-h-[500px]">
        <div className="w-24 h-24 bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-full flex items-center justify-center mb-6">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-12 h-12">
            <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 15.75l5.159-5.159a2.25 2.25 0 013.182 0l5.159 5.159m-1.5-1.5l1.409-1.409a2.25 2.25 0 013.182 0l2.909 2.909m-18 3.75h16.5a1.5 1.5 0 001.5-1.5V6a1.5 1.5 0 00-1.5-1.5H3.75A1.5 1.5 0 002.25 6v12a1.5 1.5 0 001.5 1.5zm10.5-11.25h.008v.008h-.008V8.25zm.375 0a.375.375 0 11-.75 0 .375.375 0 01.75 0z" />
            </svg>
        </div>
        <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">Chưa có thiết kế nào</h3>
        <p className="text-gray-500 dark:text-gray-400 max-w-md">
            Tải lên mẫu tham khảo và hình ảnh sản phẩm ở bảng bên phải, sau đó nhấn <strong>"Tạo thiết kế"</strong> để bắt đầu.
        </p>
      </div>
    );
  }

  const downloadImage = (url: string, id: string) => {
    const link = document.createElement('a');
    link.href = url;
    link.download = `banner-clone-${id}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDownloadAll = () => {
    images.forEach((img, index) => {
        setTimeout(() => {
            downloadImage(img.url, img.id);
        }, index * 500); // Stagger downloads to prevent browser blocking
    });
  };

  return (
    <div className="w-full h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <span>Kết quả</span>
            {isGenerating && (
                <span className="text-sm font-normal text-blue-500 animate-pulse bg-blue-50 dark:bg-blue-900/30 px-3 py-1 rounded-full">
                    Đang tạo {expectedCount} biến thể...
                </span>
            )}
            {!isGenerating && images.length > 0 && (
                <span className="text-sm font-normal text-gray-500 dark:text-gray-400 px-3 py-1">
                    {images.length} thiết kế hoàn thành
                </span>
            )}
          </h2>

          {images.length > 0 && !isGenerating && (
              <button 
                onClick={handleDownloadAll}
                className="flex items-center gap-2 px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg text-sm font-medium transition-colors shadow-sm"
              >
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5M16.5 12L12 16.5m0 0L7.5 12m4.5 4.5V3" />
                  </svg>
                  Tải tất cả
              </button>
          )}
      </div>

      {/* Grid container with variable aspect ratios handled by children */}
      <div className="grid grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-6 overflow-y-auto pb-10 pr-2 custom-scrollbar auto-rows-min">
        {images.map((img) => (
          <div 
            key={img.id} 
            className="group relative bg-white dark:bg-gray-800 rounded-xl overflow-hidden shadow-lg border border-gray-200 dark:border-gray-700 hover:border-blue-500 dark:hover:border-blue-500 transition-all duration-300 h-fit"
            onClick={() => { setSelectedImage(img); setIsLightboxEditing(false); }}
          >
            <div className={`w-full bg-gray-100 dark:bg-gray-900 flex items-center justify-center overflow-hidden relative ${getAspectClass(img.aspectRatio)}`}>
                <img
                  src={img.url}
                  alt={`Generated ${img.style}`}
                  className={`w-full h-full object-cover transition-transform duration-500 ${editingId !== img.id ? 'group-hover:scale-105' : ''}`}
                />

                {/* Loading Overlay for Regeneration */}
                {img.isRegenerating && (
                    <div className="absolute inset-0 z-20 bg-black/60 backdrop-blur-sm flex flex-col items-center justify-center">
                        <div className="w-8 h-8 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin mb-2"></div>
                        <span className="text-white text-xs font-medium animate-pulse">Đang chỉnh sửa...</span>
                    </div>
                )}

                {/* Edit Mode Overlay */}
                {editingId === img.id && !img.isRegenerating && (
                    <div 
                        className="absolute inset-0 z-20 bg-black/80 backdrop-blur-sm flex flex-col items-center justify-center p-4 animate-in fade-in duration-200"
                        onClick={(e) => e.stopPropagation()}
                    >
                        <h4 className="text-white font-bold text-sm mb-2">Chỉnh sửa thiết kế</h4>
                        <textarea 
                            className="w-full h-24 bg-gray-800 text-white text-sm rounded-lg border border-gray-600 p-2 mb-3 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none resize-none"
                            placeholder="Nhập yêu cầu (VD: Đổi nền đỏ, làm logo to hơn...)"
                            autoFocus
                            value={editPrompt}
                            onChange={(e) => setEditPrompt(e.target.value)}
                        />
                        <div className="flex gap-2 w-full">
                            <button 
                                onClick={(e) => handleCancelEdit(e)}
                                className="flex-1 py-2 bg-gray-600 hover:bg-gray-500 text-white text-xs font-bold rounded-lg"
                            >
                                Hủy
                            </button>
                            <button 
                                onClick={(e) => handleSubmitEdit(e, img.id)}
                                className="flex-1 py-2 bg-blue-600 hover:bg-blue-500 text-white text-xs font-bold rounded-lg"
                            >
                                Xác nhận
                            </button>
                        </div>
                    </div>
                )}
            </div>

            {/* Hover Actions (Only visible if not editing) */}
            {editingId !== img.id && !img.isRegenerating && (
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-end p-3 pointer-events-none">
                <div className="flex gap-2 pointer-events-auto">
                    {/* Regenerate Button */}
                    <button
                        onClick={(e) => handleEditClick(e, img.id)}
                        className="w-8 py-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg flex items-center justify-center shadow-lg transition-transform hover:scale-105"
                        title="Chỉnh sửa / Regenerate"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09z" />
                        </svg>
                    </button>

                    <button
                        onClick={(e) => { e.stopPropagation(); downloadImage(img.url, img.id); }}
                        className="flex-1 py-2 bg-blue-600 hover:bg-blue-500 text-white text-xs font-bold rounded-lg shadow-lg flex items-center justify-center gap-1 transition-transform hover:scale-105"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-3 h-3">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5M16.5 12L12 16.5m0 0L7.5 12m4.5 4.5V3" />
                        </svg>
                        Tải về
                    </button>
                    <button
                        onClick={(e) => { e.stopPropagation(); setSelectedImage(img); setIsLightboxEditing(false); }}
                        className="w-8 py-2 bg-white/20 hover:bg-white/40 backdrop-blur-sm text-white rounded-lg flex items-center justify-center transition-transform hover:scale-105"
                        title="Phóng to"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-5.197-5.197m0 0A7.5 7.5 0 105.196 5.196a7.5 7.5 0 0010.607 10.607zM10.5 7.5v6m3-3h-6" />
                        </svg>
                    </button>
                </div>
                </div>
            )}
          </div>
        ))}

        {isGenerating && Array.from({ length: expectedCount - images.length }).map((_, idx) => (
            <div key={`loading-${idx}`} className="bg-gray-100 dark:bg-gray-800/50 rounded-xl border border-gray-200 dark:border-gray-700 aspect-[3/4] flex flex-col items-center justify-center animate-pulse p-4">
                <div className="w-10 h-10 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin mb-4"></div>
                <div className="h-2 w-2/3 bg-gray-300 dark:bg-gray-700 rounded mb-2"></div>
                <div className="h-2 w-1/2 bg-gray-300 dark:bg-gray-700 rounded"></div>
                <span className="text-xs text-gray-400 mt-2">Đang xử lý...</span>
            </div>
        ))}
      </div>

      {/* Lightbox / Zoom Modal */}
      {selectedImage && (
        <div 
            className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-md flex items-center justify-center p-4"
            onClick={() => setSelectedImage(null)}
        >
            <div className="relative max-w-5xl max-h-[90vh] w-full h-full flex flex-col items-center justify-center" onClick={(e) => e.stopPropagation()}>

                {/* Image Container */}
                <div className="relative flex-1 flex items-center justify-center overflow-hidden">
                    <img 
                        src={selectedImage.url} 
                        alt="Zoomed Result" 
                        className="max-w-full max-h-[80vh] object-contain rounded-lg shadow-2xl"
                    />
                </div>

                {/* Lightbox Controls */}
                <div className="mt-4 w-full flex flex-col gap-3">
                     {/* Edit Input Area */}
                     <div className="flex gap-2 w-full max-w-2xl mx-auto">
                        <input 
                            type="text" 
                            value={lightboxPrompt}
                            onChange={(e) => setLightboxPrompt(e.target.value)}
                            onFocus={() => setIsLightboxEditing(true)}
                            placeholder="Nhập yêu cầu sửa ảnh (VD: Đổi nền đen, thêm logo...)"
                            className="flex-1 bg-white/10 border border-white/20 text-white rounded-full px-4 py-3 outline-none focus:border-blue-500 focus:bg-white/20 transition-all placeholder-gray-400"
                        />
                        <button 
                            onClick={handleLightboxRegenerate}
                            disabled={!lightboxPrompt.trim()}
                            className="bg-purple-600 hover:bg-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-6 py-2 rounded-full font-bold transition-all flex items-center gap-2"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09z" />
                            </svg>
                            Sửa ngay
                        </button>
                     </div>

                     {/* Top Right Actions */}
                     <div className="absolute top-4 right-4 flex gap-2">
                        <button
                            onClick={(e) => { e.stopPropagation(); downloadImage(selectedImage.url, selectedImage.id); }}
                            className="p-3 bg-blue-600 hover:bg-blue-500 text-white rounded-full shadow-lg transition-transform hover:scale-105"
                            title="Tải xuống"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5M16.5 12L12 16.5m0 0L7.5 12m4.5 4.5V3" />
                            </svg>
                        </button>
                        <button
                            onClick={() => setSelectedImage(null)}
                            className="p-3 bg-white/10 hover:bg-white/30 text-white rounded-full shadow-lg backdrop-blur-md transition-colors"
                            title="Đóng"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                            </svg>
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export interface GeneratedImage {
  id: string;
  url: string;
  style: string;
  aspectRatio: string; // Store the aspect ratio used to generate this image
  isRegenerating?: boolean; // Loading state for specific image
}

export interface GenerationState {
  isGenerating: boolean;
  error: string | null;
  results: GeneratedImage[];
}

export type DesignStyle = 'Sao chép chính xác' | 'Hiện đại & Tối giản' | 'Nổi bật & Sống động' | 'Sang trọng & Thanh lịch' | 'Sáng tạo phá cách';

export const STYLES: DesignStyle[] = [
  'Sao chép chính xác',
  'Hiện đại & Tối giản',
  'Nổi bật & Sống động',
  'Sang trọng & Thanh lịch',
  'Sáng tạo phá cách'
];

export type TypographyStyle = 
  | 'Tự động' 
  | 'Làm đẹp, thời trang, mềm mại' 
  | 'Cách điệu, dễ thương' 
  | 'Tươi trẻ, màu sắc' 
  | 'Chuyên nghiệp, hiện đại' 
  | 'Hoài cổ (Retro/Vintage)' 
  | 'Mạnh mẽ, nổi bật';

export const TYPOGRAPHY_STYLES: TypographyStyle[] = [
  'Tự động',
  'Làm đẹp, thời trang, mềm mại',
  'Cách điệu, dễ thương',
  'Tươi trẻ, màu sắc',
  'Chuyên nghiệp, hiện đại',
  'Hoài cổ (Retro/Vintage)',
  'Mạnh mẽ, nổi bật'
];

export interface GenerationSettings {
  theme: 'dark' | 'light';
  quantity: number;
  aspectRatio: '1:1' | '3:4' | '4:3' | '16:9' | '9:16';
  quality: '1K' | '2K' | '4K';
  typography: TypographyStyle;
}

export const DEFAULT_SETTINGS: GenerationSettings = {
  theme: 'dark',
  quantity: 4,
  aspectRatio: '3:4',
  quality: '1K',
  typography: 'Tự động'
};

import React, { useState, useEffect } from 'react';
import { MultiImageUpload } from './components/MultiImageUpload';
import { Gallery } from './components/Gallery';
import { generateBanner, editBanner } from './services/geminiService';
import { GeneratedImage, GenerationState, STYLES, GenerationSettings, DEFAULT_SETTINGS, TYPOGRAPHY_STYLES } from './types';

const App: React.FC = () => {
  const [referenceImages, setReferenceImages] = useState<string[]>([]);
  const [productImages, setProductImages] = useState<string[]>([]);

  // Input states
  const [brandDescription, setBrandDescription] = useState<string>('');
  const [promoInfo, setPromoInfo] = useState<string>('');
  const [prompt, setPrompt] = useState<string>('');

  const [settings, setSettings] = useState<GenerationSettings>(DEFAULT_SETTINGS);

  const [state, setState] = useState<GenerationState>({
    isGenerating: false,
    error: null,
    results: []
  });

  // API Key Selection State
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [isCheckingKey, setIsCheckingKey] = useState<boolean>(true);

  // Check for API Key on mount
  useEffect(() => {
    const checkKey = async () => {
      try {
        const win = window as any;
        if (win.aistudio?.hasSelectedApiKey) {
          const hasKey = await win.aistudio.hasSelectedApiKey();
          setHasApiKey(hasKey);
        } else {
          setHasApiKey(true);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
        setHasApiKey(true);
      } finally {
        setIsCheckingKey(false);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    const win = window as any;
    if (win.aistudio?.openSelectKey) {
      await win.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  useEffect(() => {
    if (settings.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [settings.theme]);

  const toggleTheme = () => {
    setSettings(prev => ({ ...prev, theme: prev.theme === 'dark' ? 'light' : 'dark' }));
  };

  const handleGenerate = async () => {
    if (referenceImages.length === 0 || productImages.length === 0) {
      setState(prev => ({ ...prev, error: 'Vui lòng tải lên ít nhất một mẫu thiết kế tham khảo và một hình ảnh sản phẩm.' }));
      return;
    }

    setState({
      isGenerating: true,
      error: null,
      results: []
    });

    try {
      const tasks = [];
      for (let i = 0; i < settings.quantity; i++) {
        const style = STYLES[i % STYLES.length];
        tasks.push(async () => {
             const resultBase64 = await generateBanner(
                referenceImages,
                productImages,
                brandDescription,
                promoInfo,
                prompt,
                style,
                settings
              );

              const imgData: GeneratedImage = {
                  id: crypto.randomUUID(),
                  url: resultBase64,
                  style: style,
                  aspectRatio: settings.aspectRatio
              };
              return imgData;
        });
      }

      const promises = tasks.map(async (task) => {
          try {
              const img = await task();
              setState(prev => ({
                ...prev,
                results: [...prev.results, img]
              }));
          } catch (err: any) {
              console.error("Generation failed for task", err);
              if (err.message && (err.message.includes("Permission Denied") || err.message.includes("403") || err.message.includes("Requested entity was not found"))) {
                 setHasApiKey(false);
                 throw new Error("Quyền truy cập bị từ chối. Vui lòng chọn một khóa API trả phí hợp lệ.");
              }
              throw err;
          }
      });

      await Promise.all(promises);

    } catch (error: any) {
      setState(prev => ({ 
        ...prev, 
        error: error.message || 'Đã xảy ra lỗi không mong muốn trong quá trình tạo.' 
      }));
    } finally {
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const handleRegenerate = async (id: string, editPrompt: string) => {
      // Find the image to regenerate
      const imageIndex = state.results.findIndex(img => img.id === id);
      if (imageIndex === -1) return;

      const currentImage = state.results[imageIndex];

      // Set regeneration state for this specific image
      setState(prev => {
          const newResults = [...prev.results];
          newResults[imageIndex] = { ...newResults[imageIndex], isRegenerating: true };
          return { ...prev, results: newResults };
      });

      try {
          const newBase64 = await editBanner(
              currentImage.url,
              editPrompt,
              currentImage.aspectRatio
          );

          // Update with new image
          setState(prev => {
              const newResults = [...prev.results];
              newResults[imageIndex] = { 
                  ...newResults[imageIndex], 
                  url: newBase64, 
                  isRegenerating: false 
              };
              return { ...prev, results: newResults };
          });

      } catch (error: any) {
          console.error("Regeneration failed", error);
           setState(prev => {
              const newResults = [...prev.results];
              newResults[imageIndex] = { ...newResults[imageIndex], isRegenerating: false };
              return { 
                  ...prev, 
                  results: newResults,
                  error: error.message || "Lỗi khi chỉnh sửa ảnh."
              };
          });
      }
  };

  // Loading Screen
  if (isCheckingKey) {
    return (
        <div className="min-h-screen bg-gray-900 flex items-center justify-center">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
        </div>
    );
  }

  // API Key Selection Screen
  if (!hasApiKey) {
      return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-white flex flex-col items-center justify-center p-4 transition-colors duration-300">
            <div className="max-w-md w-full text-center space-y-8 bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-200 dark:border-gray-700">
                <div>
                    <h1 className="text-3xl font-extrabold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 dark:from-blue-400 dark:to-purple-500 mb-2">
                        BannerClone AI
                    </h1>
                    <p className="text-gray-600 dark:text-gray-400">
                        Tạo thiết kế banner chuyên nghiệp
                    </p>
                </div>

                <div className="py-4">
                    <p className="text-lg font-medium mb-2">Yêu cầu khóa API</p>
                    <p className="text-gray-500 dark:text-gray-400 text-sm mb-6">
                        Để sử dụng mô hình <strong>Gemini 3 Pro</strong>, bạn cần chọn khóa API từ dự án Google Cloud có trả phí.
                    </p>

                    <button
                        onClick={handleSelectKey}
                        className="w-full py-3 px-6 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-lg transform transition-all hover:scale-[1.02] active:scale-95"
                    >
                        Chọn Khóa API Trả phí
                    </button>
                </div>
            </div>
        </div>
      );
  }

  return (
    <div className={`flex h-screen overflow-hidden bg-gray-50 dark:bg-[#0f1115] text-gray-900 dark:text-white transition-colors duration-300`}>

        {/* Left Column: Results/History Area */}
        <div className="flex-1 h-full overflow-hidden flex flex-col p-6 lg:p-8">
            <header className="mb-6 flex justify-between items-center">
               <div className="flex items-center gap-3">
                  <div className="bg-gradient-to-r from-blue-600 to-purple-600 w-10 h-10 rounded-xl flex items-center justify-center shadow-lg">
                      <span className="text-white font-bold text-xl">B</span>
                  </div>
                  <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 dark:from-blue-400 dark:to-purple-500">
                    BannerClone AI
                  </h1>
               </div>

               <div className="flex items-center gap-4">
                  <button 
                      onClick={toggleTheme}
                      className="p-2 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-all"
                      title={settings.theme === 'dark' ? "Chuyển sang chế độ Sáng" : "Chuyển sang chế độ Tối"}
                  >
                      {settings.theme === 'dark' ? (
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M12 3v2.25m6.364.386l-1.591 1.591M21 12h-2.25m-.386 6.364l-1.591-1.591M12 18.75V21m-4.773-4.227l-1.591 1.591M5.25 12H3m4.227-4.773L5.636 5.636M15.75 12a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0z" />
                      </svg>
                      ) : (
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M21.752 15.002A9.718 9.718 0 0118 15.75c-5.385 0-9.75-4.365-9.75-9.75 0-1.33.266-2.597.748-3.752A9.753 9.753 0 003 11.25C3 16.635 7.365 21 12.75 21a9.753 9.753 0 009.002-5.998z" />
                      </svg>
                      )}
                  </button>
               </div>
            </header>

            <Gallery 
                images={state.results} 
                isGenerating={state.isGenerating} 
                expectedCount={settings.quantity}
                onRegenerate={handleRegenerate}
            />
        </div>

        {/* Right Column: Sidebar (Inputs & Settings) */}
        <div className="w-full lg:w-[420px] bg-white dark:bg-[#1a1d24] h-full overflow-y-auto border-l border-gray-200 dark:border-gray-800 shadow-2xl flex flex-col z-20 custom-scrollbar">
            <div className="p-6 space-y-8">
                {/* Upload Section */}
                <div className="space-y-6">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-gray-800 pb-2">
                         <span className="bg-blue-100 dark:bg-blue-900/50 text-blue-600 dark:text-blue-400 rounded-lg p-1">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                 <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" />
                             </svg>
                         </span>
                        Tài nguyên
                    </h2>
                    <MultiImageUpload
                        label="Mẫu thiết kế (Reference)"
                        description="Tải lên mẫu banner bạn muốn học theo"
                        images={referenceImages}
                        onImagesChange={setReferenceImages}
                    />
                    <MultiImageUpload
                        label="Sản phẩm (Assets)"
                        description="Tải lên ảnh sản phẩm cần ghép"
                        images={productImages}
                        onImagesChange={setProductImages}
                    />
                </div>

                {/* Prompt Section */}
                <div className="space-y-5">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-gray-800 pb-2">
                        <span className="bg-purple-100 dark:bg-purple-900/50 text-purple-600 dark:text-purple-400 rounded-lg p-1">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                 <path strokeLinecap="round" strokeLinejoin="round" d="M16.862 4.487l1.687-1.688a1.875 1.875 0 112.652 2.652L10.582 16.07a4.5 4.5 0 01-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 011.13-1.897l8.932-8.931zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0115.75 21H5.25A2.25 2.25 0 013 18.75V8.25A2.25 2.25 0 015.25 6H10" />
                             </svg>
                         </span>
                        Thông tin & Yêu cầu
                    </h2>

                    <div>
                        <label htmlFor="brandDescription" className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-2 uppercase">
                            Mô tả thương hiệu
                        </label>
                        <textarea
                            id="brandDescription"
                            rows={2}
                            className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-xl p-3 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all resize-none text-sm"
                            placeholder="Ví dụ: Thương hiệu thời trang cao cấp, tối giản..."
                            value={brandDescription}
                            onChange={(e) => setBrandDescription(e.target.value)}
                        />
                    </div>

                    <div>
                        <label htmlFor="promoInfo" className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-2 uppercase">
                            Thông tin khuyến mãi (Tùy chọn)
                        </label>
                        <textarea
                            id="promoInfo"
                            rows={2}
                            className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-xl p-3 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all resize-none text-sm"
                            placeholder="Ví dụ: Giảm 50%, Mua 1 tặng 1, Freeship..."
                            value={promoInfo}
                            onChange={(e) => setPromoInfo(e.target.value)}
                        />
                    </div>

                    <div>
                        <label htmlFor="prompt" className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-2 uppercase">
                            Yêu cầu tùy chỉnh (Tùy chọn)
                        </label>
                        <textarea
                            id="prompt"
                            rows={3}
                            className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-xl p-3 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all resize-none text-sm"
                            placeholder="Ví dụ: Đổi nền sang màu xanh biển, thêm chữ 'Giảm giá mùa hè'..."
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                        />
                    </div>
                </div>

                {/* Settings Section */}
                <div className="space-y-5">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-gray-800 pb-2">
                        <span className="bg-green-100 dark:bg-green-900/50 text-green-600 dark:text-green-400 rounded-lg p-1">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                                 <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 6h9.75M10.5 6a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 10-3 0M3.75 6H7.5m3 12h9.75m-9.75 0a1.5 1.5 0 01-3 0m3 0a1.5 1.5 0 00-3 0m-3.75 0H7.5m9-6h3.75m-3.75 0a1.5 1.5 0 01-3 0m3 0a1.5 1.5 0 00-3 0m-9.75 0h9.75" />
                             </svg>
